import api from './api'
import type { Refund } from '@/types'

export interface RequestCustomerRefundPayload {
  transactionId: string
  amount: number
  reason: string
}

export const refundService = {
  requestByCustomer: async (payload: RequestCustomerRefundPayload): Promise<Refund> => {
    const response = await api.post<Refund>('/api/v1/refunds/request', payload)
    return response.data
  },
  requestByCustomerWithToken: async (payload: RequestCustomerRefundPayload, token: string): Promise<Refund> => {
    // Use a fresh axios instance to avoid global auth header (merchant token) being sent.
    const axios = await import('axios').then(m => m.default)
    const baseURL = (await import('./api')).default.defaults.baseURL || ''
    const client = axios.create({ baseURL })
    const response = await client.post<Refund>('/api/v1/refunds/request', payload, {
      headers: { Authorization: `Bearer ${token}` },
    })
    return response.data
  },
}


